/* ========== Build Flagship Content ========== */
function buildFlagshipContent(metro) {
  const cd = CITY_LEGAL_DATA[metro.slug];
  if (!cd) return null;

  const city = metro.display;

  let html = `\n${flagshipCSS()}\n`;
  html += `${MARKER_START}\n`;
  html += hourlyRates(city, cd);
  html += barAndReferrals(city, cd);
  html += legalAid(city, cd);
  html += contingencyAndFees(city, cd);
  html += courtCosts(city, cd);
  html += mediation(city, cd);
  html += commonDisputes(city, cd);
  html += redFlagsSection(city, cd);
  html += proBonoSection(city, cd);
  html += onlineLegal(city, cd);
  html += courtBacklog(city, cd);
  html += buyerQuestions(city, cd);
  html += `\n${MARKER_END}\n`;

  return html;
}

/* ========== Main ========== */
function main() {
  let processed = 0;
  let skipped = 0;
  let created = 0;
  let totalWords = 0;

  for (const metro of METROS) {
    const filepath = path.join(ROOT, metro.file);

    // Create city page if it doesn't exist
    if (!fs.existsSync(filepath)) {
      const pageHTML = generateCityPageHTML(metro);
      if (!DRY) fs.writeFileSync(filepath, pageHTML, "utf8");
      created++;
      console.log(`  CREATED ${metro.file}`);
    }

    const flagshipHTML = buildFlagshipContent(metro);
    if (!flagshipHTML) {
      console.log(`  SKIP ${metro.file} (no data for ${metro.slug})`);
      skipped++;
      continue;
    }

    let content = fs.readFileSync(filepath, "utf8");
    const re = new RegExp(`${MARKER_START}[\\s\\S]*?${MARKER_END}\\n?`, "g");
    content = content.replace(re, "");

    const nl = content.includes("\r\n") ? "\r\n" : "\n";
    const flagshipContent = flagshipHTML.replace(/\n/g, nl);

    const uniqueGuideEnd = content.indexOf("<!-- /UNIQUE-LOCAL-GUIDE -->");
    const mainEnd = content.indexOf("</main>");
    let insertAt;
    if (uniqueGuideEnd >= 0) {
      insertAt = uniqueGuideEnd + "<!-- /UNIQUE-LOCAL-GUIDE -->".length;
    } else if (mainEnd >= 0) {
      insertAt = mainEnd;
    } else {
      console.log(`  SKIP ${metro.file} (no injection point found)`);
      skipped++;
      continue;
    }

    content = content.slice(0, insertAt) + nl + flagshipContent + nl + content.slice(insertAt);
    if (!DRY) fs.writeFileSync(filepath, content, "utf8");

    const wordCount = flagshipHTML.replace(/<[^>]+>/g, " ").split(/\s+/).filter(Boolean).length;
    totalWords += wordCount;
    console.log(`  ${metro.file}: ~${wordCount} words`);
    processed++;
  }

  const avgWords = processed > 0 ? Math.round(totalWords / processed) : 0;
  console.log(`\nDone: ${processed} processed, ${skipped} skipped, ${created} city pages created.`);
  console.log(`Average words per page: ${avgWords}`);
  if (DRY) console.log("[DRY RUN]");
}

main();
